const crypto = require('crypto');
const https = require('https');

const appId = $env.GITHUB_APP_ID;
const installationId = $env.GITHUB_INSTALLATION_ID;
const privateKeyBase64 = $env.GITHUB_PRIVATE_KEY_BASE64;
const privateKey = Buffer.from(privateKeyBase64, 'base64').toString('utf8');

const now = Math.floor(Date.now() / 1000);
const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
const payload = Buffer.from(JSON.stringify({ iat: now - 60, exp: now + 600, iss: appId })).toString('base64url');
const signature = crypto.sign('SHA256', Buffer.from(`${header}.${payload}`), privateKey).toString('base64url');
const jwt = `${header}.${payload}.${signature}`;

const token = await new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.github.com',
    path: `/app/installations/${installationId}/access_tokens`,
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${jwt}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-orchestrator',
      'Content-Length': 0
    }
  }, res => {
    let body = '';
    res.on('data', c => body += c);
    res.on('end', () => {
      if (res.statusCode !== 201) reject(new Error(`GitHub token request failed: ${res.statusCode} ${body}`));
      else resolve(JSON.parse(body).token);
    });
  });
  req.on('error', reject);
  req.end();
});

return [{ json: { ...$input.first().json, githubToken: token } }];

const https = require('https');
const data = $input.first().json;
const token = data.githubToken;
const owner = data.body.repoOwner;
const repo = data.body.repoName;
const labels = data.body.labels || data.labels || [];

// Extract epic number from epic-N label
const epicNLabel = labels.find(l => /^epic-\d+$/.test(l)) || data.body.epicNLabel || '';
const epicNumberMatch = epicNLabel.match(/^epic-(\d+)$/);
if (!epicNumberMatch) {
  return [{ json: { skipped: true, reason: 'No epic-N label found' } }];
}
const epicNumber = parseInt(epicNumberMatch[1], 10);

// --- Shared REST helper with retry/rate-limit logic ---
function _rawRequest(method, path, body, tkn) {
  return new Promise((resolve, reject) => {
    const bodyStr = body ? JSON.stringify(body) : '';
    const headers = {
      'Authorization': `Bearer ${tkn}`,
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-orchestrator',
      'X-GitHub-Api-Version': '2022-11-28'
    };
    if (body) {
      headers['Content-Type'] = 'application/json';
      headers['Content-Length'] = Buffer.byteLength(bodyStr);
    }
    const req = https.request({ hostname: 'api.github.com', path, method, headers }, res => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => {
        let parsed;
        try { parsed = JSON.parse(d); } catch(e) { parsed = d; }
        resolve({ status: res.statusCode, data: parsed, headers: res.headers });
      });
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

async function githubRest(method, path, body, maxRetries = 3) {
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    const result = await _rawRequest(method, path, body, token);
    if (result.status >= 200 && result.status < 300) return result;
    if (result.status === 403 || result.status === 429) {
      const retryAfter = result.headers['retry-after'];
      const rateLimitReset = result.headers['x-ratelimit-reset'];
      let waitMs;
      if (retryAfter) waitMs = parseInt(retryAfter, 10) * 1000;
      else if (rateLimitReset) waitMs = Math.max((parseInt(rateLimitReset, 10) * 1000) - Date.now(), 1000);
      else waitMs = Math.pow(2, attempt) * 1000;
      if (attempt < maxRetries) { await new Promise(r => setTimeout(r, waitMs)); continue; }
    }
    if (result.status >= 400 && result.status < 500) throw new Error(`GitHub API ${result.status}: ${JSON.stringify(result.data)}`);
    if (result.status >= 500 && attempt < maxRetries) { await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 1000)); continue; }
    throw new Error(`GitHub API failed after ${maxRetries + 1} attempts: ${result.status}`);
  }
}

async function transitionStatus(issueNum, newStatus) {
  const current = await githubRest('GET', `/repos/${owner}/${repo}/issues/${issueNum}/labels`);
  const currentLabels = current.data.map(l => l.name);
  const oldStatuses = currentLabels.filter(l => l.startsWith('status:'));
  for (const old of oldStatuses) {
    try { await githubRest('DELETE', `/repos/${owner}/${repo}/issues/${issueNum}/labels/${encodeURIComponent(old)}`); }
    catch (e) { if (!e.message.includes('404')) throw e; }
  }
  await githubRest('POST', `/repos/${owner}/${repo}/issues/${issueNum}/labels`, { labels: [newStatus] });
}

// === Get all issues with this epic-N label (open + closed) ===
let allStories = [];
for (const state of ['open', 'closed']) {
  let page = 1;
  while (true) {
    const result = await githubRest('GET', `/repos/${owner}/${repo}/issues?labels=${encodeURIComponent(epicNLabel)}&state=${state}&per_page=100&page=${page}`);
    if (result.data.length === 0) break;
    allStories = allStories.concat(result.data.filter(i => !i.pull_request && i.number !== epicNumber));
    if (result.data.length < 100) break;
    page++;
  }
}

const openStories = allStories.filter(s => s.state === 'open');
const closedStories = allStories.filter(s => s.state === 'closed');

// Categorize open stories by status
const openByStatus = {};
for (const story of openStories) {
  const storyLabels = story.labels.map(l => l.name);
  const status = storyLabels.find(l => l.startsWith('status:')) || 'unknown';
  if (!openByStatus[status]) openByStatus[status] = [];
  openByStatus[status].push(story.number);
}

const inProgress = openByStatus['status:in-progress'] || [];
const ready = openByStatus['status:ready'] || [];
const inReview = openByStatus['status:in-review'] || [];
const blocked = openByStatus['status:blocked'] || [];

// === Decision logic ===
if (openStories.length === 0) {
  // All stories are closed — trigger epic close check
  // For now, we do the close check inline (Phase 4 will extract to separate workflow)
  // Simple close: post comment and close the epic
  await githubRest('POST', `/repos/${owner}/${repo}/issues/${epicNumber}/comments`, {
    body: `## All Stories Complete\n\nAll ${closedStories.length} stories for this epic have been closed. Running post-epic checks...\n\n_TODO: Post-epic quality checks will be implemented in a future phase. Closing epic for now._`
  });
  await githubRest('PATCH', `/repos/${owner}/${repo}/issues/${epicNumber}`, { state: 'closed' });
  return [{ json: { action: 'epic-closed', epicNumber, totalStories: closedStories.length } }];
}

if (inProgress.length === 0 && ready.length === 0 && blocked.length === 0 && inReview.length > 0) {
  // All remaining open stories are in-review — move epic to in-review
  await transitionStatus(epicNumber, 'status:in-review');
  return [{ json: { action: 'epic-to-in-review', epicNumber, storiesInReview: inReview.length } }];
}

// Otherwise: epic stays in current state, stories are still being worked on
return [{ json: { action: 'no-change', epicNumber, open: openStories.length, closed: closedStories.length, inProgress: inProgress.length, ready: ready.length, inReview: inReview.length, blocked: blocked.length } }];
